sp_widget.client_script:
api.controller = function($scope, $window, spUtil) {
    var c = this;

    // ==========================================
    // ★FIX-2: 系统模式切换（内嵌確認ダイアログ）
    // ==========================================
    c.showConfirm = false;
    c.confirmTarget = '';

    c.toggleSystemMode = function() {
        var current = c.data.system_mode;
        c.confirmTarget = (current === 'disaster_active') ? 'peacetime' : 'disaster_active';
        c.showConfirm = true;
    };

    c.executeSystemModeChange = function() {
        c.showConfirm = false;
        c.server.get({
            action: 'admin_set_system_mode',
            mode: c.confirmTarget
        }).then(function(r) {
            if (r && r.data && r.data.success) {
                $window.location.reload();
            } else if (r && r.data && r.data.error) {
                spUtil.addErrorMessage(r.data.error);
            }
        });
    };

    // ==========================================
    // 管理员游客模拟切换
    // ==========================================
    c.toggleSimulate = function() {
        c.server.get({
            action: 'admin_toggle_simulate'
        }).then(function(r) {
            if (r && r.data && r.data.success) {
                $window.location.reload();
            }
        });
    };

    // ==========================================
    // Token管理面板
    // ==========================================
    c.showTokenPanel = false;
    c.guestOverview = null;

    c.toggleTokenPanel = function() {
        c.showTokenPanel = !c.showTokenPanel;
        if (c.showTokenPanel && !c.guestOverview) {
            c.loadGuestOverview();
        }
    };

    c.loadGuestOverview = function() {
        c.server.get({ action: 'admin_get_guest_overview' }).then(function(r) {
            if (r && r.data && r.data.guest_overview) {
                c.guestOverview = r.data.guest_overview;
            }
        });
    };

    c.revokeToken = function(tk) {
        if (!confirm('このTokenを無効化しますか？')) return;
        c.server.get({
            action: 'admin_revoke_token',
            token_sys_id: tk.sys_id
        }).then(function(r) {
            if (r && r.data && r.data.success) {
                spUtil.addInfoMessage(r.data.message);
                c.loadGuestOverview();
            }
        });
    };

    c.extendToken = function(tk) {
        c.server.get({
            action: 'admin_extend_token',
            token_sys_id: tk.sys_id
        }).then(function(r) {
            if (r && r.data && r.data.success) {
                spUtil.addInfoMessage(r.data.message);
                c.loadGuestOverview();
            }
        });
    };
};

sp_widget.css:
/* ============================================================
   KOKORO ROUTER — CSS
   只包含管理员栏和Token面板。子Widget的样式由子Widget自己承担。
   ============================================================ */

/* ServiceNow Portal原生コンポーネント非表示 */
html body nav.navbar,
html body .navbar,
html body .sp-page-header,
html body header,
html body footer { display: none !important; }
html body { padding-top: 0 !important; }

/* ★FIX-1: ルーターコンテナ — flex縦並び */
.kokoro-router {
    position: fixed;
    top: 0; left: 0; right: 0; bottom: 0;
    z-index: 999999;
    overflow: hidden;
    display: flex;
    flex-direction: column;
}

/* ★FIX-1: 管理員バー — position: relative（遮蔽なし） */
.admin-bar {
    position: relative;
    width: 100%;
    height: 36px;
    background: #1a237e;
    color: #c5cae9;
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0 16px;
    z-index: 1000001;
    font-size: 0.78rem;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
    box-shadow: 0 2px 8px rgba(0,0,0,0.3);
    flex-shrink: 0;
}

.admin-bar-left, .admin-bar-right {
    display: flex;
    align-items: center;
    gap: 12px;
}

.mode-badge {
    display: flex;
    align-items: center;
    gap: 6px;
    font-weight: 700;
}
.mode-badge i { font-size: 8px; }
.mode-peace i { color: #69f0ae; }
.mode-disaster i { color: #ff5252; animation: blink-dot 1s infinite; }

@keyframes blink-dot {
    0%, 100% { opacity: 1; }
    50% { opacity: 0.2; }
}

.sim-badge {
    background: #ff6f00;
    color: white;
    padding: 2px 10px;
    border-radius: 10px;
    font-weight: 700;
    font-size: 0.7rem;
}

.bar-btn {
    background: rgba(255,255,255,0.08);
    color: #e8eaf6;
    border: 1px solid rgba(255,255,255,0.15);
    border-radius: 6px;
    padding: 5px 14px;
    font-size: 0.75rem;
    cursor: pointer;
    transition: all 0.2s;
    font-family: inherit;
    display: flex;
    align-items: center;
    gap: 6px;
}
.bar-btn:hover {
    background: rgba(255,255,255,0.18);
    color: white;
}

/* ★FIX-1: 子Widget領域 — flex残りスペース */
.kokoro-router > div:last-child {
    flex: 1;
    overflow: auto;    /* ★ hidden → auto */
    position: relative;
}

/* 平時Widgetのfixed位置調整（管理員バーがある場合） */
.has-admin-bar .kokoro-user-container {
    top: 36px !important;
    height: calc(100vh - 36px) !important;
}

/* ---- Token管理面板 ---- */
.token-overlay {
    position: fixed;
    top: 36px; left: 0; right: 0; bottom: 0;
    background: rgba(0,0,0,0.5);
    z-index: 1000002;
    display: flex;
    justify-content: center;
    align-items: flex-start;
    padding-top: 20px;
}

.token-panel {
    background: white;
    width: 90%;
    max-width: 520px;
    max-height: 80vh;
    border-radius: 16px;
    box-shadow: 0 20px 60px rgba(0,0,0,0.25);
    overflow: hidden;
    display: flex;
    flex-direction: column;
}

.token-panel-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 18px 22px;
    border-bottom: 1px solid #e0e0e0;
}
.token-panel-header h3 {
    margin: 0; font-size: 1.1rem; font-weight: 800; color: #333;
}
.close-x {
    background: none; border: none;
    font-size: 1.5rem; color: #999; cursor: pointer;
}

.token-stats {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 10px;
    padding: 16px 22px;
    background: #f5f5f5;
}
.t-stat { text-align: center; }
.t-num { font-size: 1.5rem; font-weight: 900; color: #1a237e; }
.t-label { font-size: 0.72rem; color: #999; }

.token-list {
    overflow-y: auto;
    flex: 1;
    padding: 0 22px 16px;
}
.token-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 0;
    border-bottom: 1px solid #f0f0f0;
}
.token-detail {
    display: flex; flex-direction: column; gap: 3px;
}
.token-detail code {
    font-family: 'Courier New', monospace;
    font-size: 0.85rem;
    background: #e8eaf6;
    padding: 2px 6px;
    border-radius: 4px;
}
.token-detail small { font-size: 0.72rem; color: #999; }

.token-btns { display: flex; gap: 6px; }
.t-btn {
    width: 32px; height: 32px;
    border-radius: 8px; border: none;
    cursor: pointer;
    display: flex; align-items: center; justify-content: center;
    transition: all 0.2s; font-size: 0.85rem;
}
.t-btn.extend { background: #e3f2fd; color: #1565c0; }
.t-btn.extend:hover { background: #bbdefb; }
.t-btn.revoke { background: #ffebee; color: #c62828; }
.t-btn.revoke:hover { background: #ffcdd2; }

/* ★FIX-2: 確認ダイアログ */
.confirm-overlay {
    position: fixed;
    top: 0; left: 0; right: 0; bottom: 0;
    background: rgba(0,0,0,0.5);
    z-index: 1000010;
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 20px;
}

.confirm-card {
    background: white;
    border-radius: 20px;
    padding: 32px 28px;
    text-align: center;
    box-shadow: 0 20px 60px rgba(0,0,0,0.25);
    max-width: 360px;
    width: 100%;
    animation: confirmIn 0.2s ease-out;
}

@keyframes confirmIn {
    from { transform: scale(0.9); opacity: 0; }
    to { transform: scale(1); opacity: 1; }
}

.confirm-icon {
    font-size: 2.5rem;
    margin-bottom: 12px;
}

.confirm-card h3 {
    margin: 0 0 8px 0;
    font-size: 1.15rem;
    font-weight: 800;
    color: #333;
}

.confirm-card p {
    margin: 0 0 24px 0;
    font-size: 0.9rem;
    color: #666;
}

.confirm-btns {
    display: flex;
    gap: 12px;
    justify-content: center;
}

.confirm-btn {
    padding: 10px 28px;
    border-radius: 12px;
    border: none;
    font-size: 0.95rem;
    font-weight: 700;
    cursor: pointer;
    font-family: inherit;
    transition: all 0.15s;
}

.confirm-btn.cancel {
    background: #f5f5f5;
    color: #666;
}
.confirm-btn.cancel:hover {
    background: #e0e0e0;
}

.confirm-btn.ok.btn-danger {
    background: #c62828;
    color: white;
}
.confirm-btn.ok.btn-danger:hover {
    background: #b71c1c;
}

.confirm-btn.ok.btn-safe {
    background: #2e7d32;
    color: white;
}
.confirm-btn.ok.btn-safe:hover {
    background: #1b5e20;
}

/* レスポンシブ */
@media (max-width: 480px) {
    .admin-bar { font-size: 0.7rem; padding: 0 10px; }
    .bar-btn span { display: none; }
    .token-stats { grid-template-columns: repeat(3, 1fr); }
}

sp_widget.script:
(function() {
    // ============================================================
    // KOKORO ROUTER — Server Script
    //
    // 职责（仅此三件事）：
    //   1. 读取系统模式 → 决定注入哪个子Widget
    //   2. 读取Session → 判断管理员模拟状态
    //   3. 处理管理员专属Action (模式切换/模拟切换/Token管理)
    //
    // 不做的事：
    //   ✗ 不处理表单提交（子Widget的职责）
    //   ✗ 不处理心跳注册（子Widget的职责）
    //   ✗ 不处理好友系统（子Widget的职责）
    //   ✗ 不做CSRF验证（子Widget自己做）
    // ============================================================

    // ------------------------------------------
    // 第1步：读取系统运行模式
    // ------------------------------------------
    var SYSTEM_MODE = 'peacetime';

    try {
        var modeProp = gs.getProperty('x_1821654_kokoro_0.system_mode');
        if (modeProp === 'disaster_active') {
            SYSTEM_MODE = 'disaster_active';
        }
        // 注意：如果属性不存在，gs.getProperty() 返回 null
        // null !== 'disaster_active'，所以默认就是 peacetime
        // 这是「安全的默认值」——如果配置出错，系统不会进入灾害模式
    } catch (e) {
        SYSTEM_MODE = 'peacetime';
    }

    data.system_mode = SYSTEM_MODE;

    // ------------------------------------------
    // 第2步：判断当前用户身份
    // ------------------------------------------
    // 注意：Router只需要知道两件事：
    //   a) 是否是Admin（决定是否显示管理员栏）
    //   b) 是否是Guest（决定传给子Widget的options）
    // 具体的身份处理逻辑由子Widget自己负责

    data.is_admin = gs.hasRole('admin');
    data.user_name = gs.getUserDisplayName();

    var isGuestSession = !gs.isLoggedIn() ||
        gs.getUserName() === 'guest' ||
        gs.getUserID() === '5136503cc611227c00566377a6ee91f3';
    data.is_guest = isGuestSession;



    var session = gs.getSession();
    var simFlag = session.getClientData('kokoro_admin_simulate');
    data.is_simulating = (simFlag === 'true' && data.is_admin);

    // ------------------------------------------
    // 第4步：决定注入哪个子Widget
    // ------------------------------------------
    var targetWidget = '';

    var widgetOptions = {
        system_mode: SYSTEM_MODE,
        is_guest: isGuestSession,
        from_router: true
    };

    // ★ 核心分支：根据系统模式选择子Widget
    if (SYSTEM_MODE === 'disaster_active') {
        targetWidget = 'kokoro_user_disaster';
    } else {
        // Phase 0 阶段：这里写你现有Widget的ID
        // Phase 1 完成后：可以改为 'kokoro_user_peacetime'
        targetWidget = 'kokoro_user_peacetime';
    }

    // 管理员模拟中：覆写游客状态
    if (data.is_simulating && data.is_admin) {
        widgetOptions.is_guest = true;
        widgetOptions.simulate_guest_token =
            session.getClientData('kokoro_sim_token') || '';
    }

    // ★★★ 核心调用 ★★★
    data.mode_widget = $sp.getWidget(targetWidget, widgetOptions);

    // ------------------------------------------
    // 第5步：处理管理员Action
    // ------------------------------------------
    if (input) {

        // === 切换系统模式 ===
        if (input.action === 'admin_set_system_mode' && data.is_admin) {
            var newMode = String(input.mode || '');
            if (newMode !== 'peacetime' && newMode !== 'disaster_active') {
                data.error = '无效的模式值: ' + newMode;
                return;
            }

            try {
                // 弃用 gs.setProperty，直接以 GlideRecord 强制跨域更新，规避静默失败
                var propGr = new GlideRecord('sys_properties');
                propGr.addQuery('name', 'x_1821654_kokoro_0.system_mode');
                propGr.query();
                if (propGr.next()) {
                    propGr.setValue('value', newMode);
                    propGr.update();
                } else {
                    propGr.initialize();
                    propGr.setValue('name', 'x_1821654_kokoro_0.system_mode');
                    propGr.setValue('value', newMode);
                    propGr.insert();
                }
                data.system_mode = newMode;
                data.success = true;
                data.require_reload = true;
            } catch (propErr) {
                data.error = '模式切换写入失败，请检查跨域权限。';
                return;
            }

            // 审计日志
            try {
                var pe = new GlideRecord('x_1821654_kokoro_0_process_event');
                pe.initialize();
                pe.setValue('activity', 'SYSTEM_MODE_CHANGE: ' + newMode);
                pe.setValue('timestamp', new GlideDateTime());
                pe.setValue('user', gs.getUserID());
                pe.insert();
            } catch (logErr) {}

            return;
        }

        // === 切换管理员游客模拟 ===
        if (input.action === 'admin_toggle_simulate' && data.is_admin) {
            var currentSim = session.getClientData('kokoro_admin_simulate');

            if (currentSim === 'true') {
                session.putClientData('kokoro_admin_simulate', 'false');
                session.putClientData('kokoro_sim_token', '');
                data.is_simulating = false;
            } else {
                session.putClientData('kokoro_admin_simulate', 'true');
                session.putClientData('kokoro_sim_token', gs.generateGUID());
                data.is_simulating = true;
            }

            data.success = true;
            data.require_reload = true;
            return;
        }

        // === 获取游客Token统计 ===
        if (input.action === 'admin_get_guest_overview' && data.is_admin) {
            try {
                var overview = {
                    active_tokens: 0,
                    guest_wishes: 0,
                    guest_heartbeats: 0,
                    tokens: []
                };

                var activeGa = new GlideAggregate('x_1821654_kokoro_0_guest_token');
                activeGa.addQuery('is_active', true);
                activeGa.addQuery('expires_at', '>', new GlideDateTime());
                activeGa.addAggregate('COUNT');
                activeGa.query();
                if (activeGa.next()) {
                    overview.active_tokens = parseInt(activeGa.getAggregate('COUNT')) || 0;
                }

                var wishGa = new GlideAggregate('x_1821654_kokoro_0_silent_wish');
                wishGa.addNotNullQuery('guest_token');
                wishGa.addQuery('guest_token', '!=', '');
                wishGa.addAggregate('COUNT');
                wishGa.query();
                if (wishGa.next()) {
                    overview.guest_wishes = parseInt(wishGa.getAggregate('COUNT')) || 0;
                }

                var hbGa = new GlideAggregate('x_1821654_kokoro_0_x_1821654_kokoro_0_heartbeat');
                hbGa.addNotNullQuery('guest_token');
                hbGa.addQuery('guest_token', '!=', '');
                hbGa.addAggregate('COUNT');
                hbGa.query();
                if (hbGa.next()) {
                    overview.guest_heartbeats = parseInt(hbGa.getAggregate('COUNT')) || 0;
                }

                var tokenGr = new GlideRecord('x_1821654_kokoro_0_guest_token');
                tokenGr.addQuery('is_active', true);
                tokenGr.orderByDesc('created_at');
                tokenGr.setLimit(20);
                tokenGr.query();

                while (tokenGr.next()) {
                    overview.tokens.push({
                        sys_id: tokenGr.getUniqueValue(),
                        token_short: tokenGr.getValue('token').substring(0, 8) + '...',
                        created_at: tokenGr.getDisplayValue('created_at'),
                        expires_at: tokenGr.getDisplayValue('expires_at'),
                        linked_user: tokenGr.getDisplayValue('linked_user') || ''
                    });
                }

                data.guest_overview = overview;
                data.success = true;
            } catch (e) {
                data.error = '数据获取失败';
            }
            return;
        }

        // === 撤销Token ===
        if (input.action === 'admin_revoke_token' && data.is_admin) {
            try {
                var rSysId = String(input.token_sys_id || '');
                if (!/^[a-f0-9]{32}$/.test(rSysId)) {
                    data.error = '无效的Token ID'; return;
                }
                var rGr = new GlideRecord('x_1821654_kokoro_0_guest_token');
                if (rGr.get(rSysId)) {
                    rGr.setValue('is_active', false);
                    rGr.update();
                    data.success = true;
                    data.message = 'Token已撤销';
                } else {
                    data.error = 'Token未找到';
                }
            } catch (e) {
                data.error = '操作失败';
            }
            return;
        }

        // === 延期Token ===
        if (input.action === 'admin_extend_token' && data.is_admin) {
            try {
                var eSysId = String(input.token_sys_id || '');
                if (!/^[a-f0-9]{32}$/.test(eSysId)) {
                    data.error = '无效的Token ID'; return;
                }
                var eGr = new GlideRecord('x_1821654_kokoro_0_guest_token');
                if (eGr.get(eSysId)) {
                    var newExp = new GlideDateTime();
                    newExp.addSeconds(72 * 3600);
                    eGr.setValue('expires_at', newExp);
                    eGr.setValue('is_active', true);
                    eGr.update();
                    data.success = true;
                    data.message = 'Token延期72小时';
                } else {
                    data.error = 'Token未找到';
                }
            } catch (e) {
                data.error = '操作失败';
            }
            return;
        }
    }
})();
